config.script:
"""Created By : Akhil Aerra
	Date : 03.10.2024
	Purpose : Passing dropdown values to Parameteres""" 

if self.parent.parent.parent.getChild("cntFlex").getChild("cntArea").getChild("drpArea").props.value==-1:
	self.view.params.Area=-1
else:
	self.view.params.Area=self.parent.parent.parent.getChild("cntFlex").getChild("cntArea").getChild("drpArea").props.value
	if str(self.view.params.AreaName)=='Legacy Axle':
		self.view.params.Variant1='LD'
		self.view.params.Variant2='HD'
	elif str(self.view.params.AreaName)=='Titan Axle':
		self.view.params.Variant1='EV'
		self.view.params.Variant2='DE'
	elif str(self.view.params.AreaName)=='Legacy Transmission':
		self.view.params.Variant1='6S'
		self.view.params.Variant2='9S'
	elif str(self.view.params.AreaName)=='Titan Transmission':
		self.view.params.Variant1='HO'
		self.view.params.Variant2='VE'
